-- Q1.What is the total revenue generated by male vs. femal customers?
select gender,sum(purchase_amount) as revenue
from customer
group by gender;

-- Q2.which customers used a discount but still spend more than the average purchase amount?
select customer_id,purchase_amount
from customer
where discount_applied='Yes' and purchase_amount >= (select avg(purchase_amount) from customer);

-- Q3.Whick are the top 5 products with the highest average review rating?
select item_purchased,round(avg(review_rating),2) as 'Average Product Rating'
from customer
group by item_purchased
order by avg(review_rating) desc
limit 5;

-- Q4.Compare the average Purchase Amount between Standard and Express Shipping.
select shipping_type ,Round(avg(purchase_amount),2)
from customer
where shipping_type in ('Standard','Express')
group by shipping_type;

-- Q5.Do subscribed customers spend more?Comapre average spend and total revenue between subscribed and non-subscribed
select subscription_status,count(customer_id) as total_customer,
round(avg(purchase_amount),2) as avg_spend ,
sum(purchase_amount) as total_revenue
from customer
group by subscription_status
order by total_revenue,avg_spend;

-- Q6.Which 5 products have the highest percentage of purchases with discounts applied?
select item_purchased,
concat(round((100*sum(case when discount_applied='yes' then 1 else 0 end)/count(*)),2),'%') as discount_rate
from customer
group by item_purchased
order by discount_rate desc
limit 5;

-- Q7. Segment customers into New,Returning, and Loyal based on their total number of previous purchases,and show the count of each segment.

with customer_type as (
select customer_id,previous_purchases,
case 
	when previous_purchases=1 then 'New'
    when previous_purchases between 2 and 10 then 'Returning'
    else 'Loyal'
    end as customer_segment
from customer
)
select customer_segment,count(*) as 'Number of Customer'
from customer_type
group by customer_segment ;


-- Q8.What are the top 3 most purchased products within each category?
 with item_count as (
 select category,item_purchased,
 count(customer_id) as total_orders,
 Row_Number() OVER(PARTITION by category order by count(customer_id) DESC) as item_rank
 from customer
 group by category,item_purchased
 )
select item_rank,category,item_purchased,total_orders
from item_count
where item_rank<=3;


-- Q9.Are customer who are repeat buyers (more than 5 pervious purchases) also likely to subscribe?
select subscription_status,count(customer_id) as repeat_customer
from customer
where previous_purchases>5
group by subscription_status;

-- Q10. What is the revenue contribution of each age group?
select age_bracket,sum(purchase_amount) as total_revenue
from customer
group by age_bracket
order by total_revenue desc;




